{"tool":"newFileCreated","path":"frontend/src/index.css","content":":root {
  --bg: #0a0e17;
  --bg-card: #111827;
  --bg-card-hover: #1a2332;
  --bg-sidebar: #0d1117;
  --border: rgba(255, 255, 255, 0.06);
  --border-active: rgba(0, 210, 255, 0.3);
  --primary: #00d2ff;
  --primary-glow: rgba(0, 210, 255, 0.15);
  --success: #22c55e;
  --success-glow: rgba(34, 197, 94, 0.15);
  --danger: #ef4444;
  --danger-glow: rgba(239, 68, 68, 0.15);
  --warning: #f59e0b;
  --warning-glow: rgba(245, 158, 11, 0.15);
  --purple: #a855f7;
  --purple-glow: rgba(168, 85, 247, 0.15);
  --text: #f1f5f9;
  --text-secondary: #94a3b8;
  --text-muted: #64748b;
  --radius: 16px;
  --radius-sm: 10px;
  --radius-xs: 6px;
  --shadow: 0 4px 24px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0 8px 40px rgba(0, 0, 0, 0.4);
  --transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body, #root {
  height: 100%; width: 100%;
  background: var(--bg);
  color: var(--text);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

/* ═══ SCROLLBAR ═══ */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }

/* ═══ SPLASH ═══ */
.splash-screen {
  position: fixed; inset: 0;
  background: #000;
  z-index: 9999;
  display: flex; align-items: center; justify-content: center;
  flex-direction: column; gap: 24px;
  transition: opacity 0.6s ease;
}
.splash-screen::before {
  content: ''; position: absolute; inset: 0;
  background: radial-gradient(ellipse at 50% 50%, #0f172a 0%, #000 70%);
}
.splash-screen.splash-fade-out { opacity: 0; pointer-events: none; }
.splash-content { position: relative; z-index: 1; text-align: center; }
.splash-logo { margin-bottom: 16px; }
.splash-logo-ring {
  width: 80px; height: 80px; margin: 0 auto;
  border: 2px solid var(--primary);
  border-radius: 50%;
  animation: splash-ring 2s ease-in-out infinite;
  display: flex; align-items: center; justify-content: center;
}
@keyframes splash-ring {
  0%, 100% { transform: scale(1); opacity: 0.5; }
  50% { transform: scale(1.1); opacity: 1; }
}
.splash-logo-inner {
  width: 56px; height: 56px; margin: -68px auto 0;
  background: var(--bg-card);
  border-radius: 14px;
  display: flex; align-items: center; justify-content: center;
  position: relative; z-index: 2;
}
.splash-title {
  font-size: 2rem; font-weight: 800;
  background: linear-gradient(135deg, var(--primary), #a855f7);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  margin-top: 16px;
}
.splash-subtitle { color: var(--text-muted); font-size: 0.9rem; margin-top: 4px; }
.splash-progress {
  width: 200px; height: 3px; background: rgba(255,255,255,0.05);
  border-radius: 2px; margin: 20px auto 0; overflow: hidden;
}
.splash-progress-bar {
  height: 100%; background: linear-gradient(90deg, var(--primary), #a855f7);
  border-radius: 2px; transition: width 0.1s linear;
}
.splash-loading { color: var(--text-muted); font-size: 0.75rem; margin-top: 12px; }

/* ═══ APP LAYOUT ═══ */
.app-container {
  display: flex; height: 100vh; height: 100dvh;
  width: 100vw; overflow: hidden;
}
.app-appear { animation: app-fade-in 0.5s ease forwards; }
@keyframes app-fade-in {
  0% { opacity: 0; }
  100% { opacity: 1; }
}

/* ═══ SIDEBAR ═══ */
.sidebar {
  width: 260px; min-width: 260px;
  background: var(--bg-sidebar);
  border-right: 1px solid var(--border);
  display: flex; flex-direction: column;
  padding: 0;
  overflow-y: auto; overflow-x: hidden;
}
.sidebar-header {
  padding: 24px 20px 20px;
  border-bottom: 1px solid var(--border);
}
.sidebar-logo {
  display: flex; align-items: center; gap: 12px;
}
.sidebar-logo-icon {
  width: 40px; height: 40px;
  background: linear-gradient(135deg, var(--primary), #a855f7);
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  font-weight: 900; font-size: 1rem; color: white;
}
.sidebar-logo-text h2 {
  font-size: 1.1rem; font-weight: 800;
  background: linear-gradient(135deg, var(--primary), #a855f7);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
}
.sidebar-logo-text p {
  font-size: 0.7rem; color: var(--text-muted);
  margin-top: 2px;
}
.sidebar-user-info {
  margin-top: 16px; padding: 10px 12px;
  background: rgba(255,255,255,0.03);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; gap: 10px;
}
.sidebar-user-avatar {
  width: 32px; height: 32px;
  background: linear-gradient(135deg, var(--primary), var(--purple));
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  font-weight: 700; font-size: 0.8rem; color: white;
}
.sidebar-user-name { font-size: 0.85rem; font-weight: 600; }
.sidebar-user-role {
  font-size: 0.7rem; color: var(--text-muted);
  background: rgba(255,255,255,0.05);
  padding: 2px 8px; border-radius: 4px; margin-top: 2px;
  display: inline-block;
}

.sidebar-nav {
  flex: 1; padding: 12px 10px;
  display: flex; flex-direction: column; gap: 2px;
}
.sidebar-section-label {
  font-size: 0.65rem; font-weight: 700;
  color: var(--text-muted); text-transform: uppercase;
  letter-spacing: 1px; padding: 16px 10px 6px;
}
.sidebar-tab {
  display: flex; align-items: center; gap: 12px;
  padding: 10px 12px;
  background: transparent; border: none;
  color: var(--text-secondary);
  font-size: 0.85rem; font-weight: 500;
  border-radius: var(--radius-sm);
  cursor: pointer; transition: var(--transition);
  width: 100%; text-align: left;
}
.sidebar-tab:hover {
  background: rgba(255,255,255,0.04);
  color: var(--text);
}
.sidebar-tab.active {
  background: var(--primary-glow);
  color: var(--primary);
  font-weight: 600;
}
.sidebar-tab.active svg { color: var(--primary); }
.sidebar-tab svg { color: var(--text-muted); flex-shrink: 0; }

.sidebar-footer {
  padding: 16px;
  border-top: 1px solid var(--border);
}
.sidebar-time {
  font-size: 0.8rem; color: var(--text-muted);
  text-align: center; margin-bottom: 10px;
  font-variant-numeric: tabular-nums;
}
.sidebar-logout {
  display: flex; align-items: center; justify-content: center; gap: 8px;
  width: 100%; padding: 10px;
  background: rgba(239, 68, 68, 0.08);
  border: 1px solid rgba(239, 68, 68, 0.15);
  color: var(--danger); border-radius: var(--radius-sm);
  font-size: 0.85rem; font-weight: 600;
  cursor: pointer; transition: var(--transition);
}
.sidebar-logout:hover {
  background: rgba(239, 68, 68, 0.15);
}

/* ═══ MAIN CONTENT ═══ */
.main-content {
  flex: 1; padding: 20px;
  background: var(--bg);
  overflow: auto; display: flex; flex-direction: column;
  min-width: 0; min-height: 0;
}

/* ═══ PAGE HEADER ═══ */
.page-header {
  display: flex; align-items: center; justify-content: space-between;
  margin-bottom: 20px; flex-shrink: 0;
}
.page-title {
  font-size: 1.5rem; font-weight: 800;
}
.page-subtitle {
  font-size: 0.85rem; color: var(--text-muted); margin-top: 2px;
}

/* ═══ STATS ROW ═══ */
.stats-row {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 12px; margin-bottom: 20px; flex-shrink: 0;
}
.stat-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px 20px;
  transition: var(--transition);
}
.stat-card:hover {
  border-color: var(--border-active);
  transform: translateY(-2px);
  box-shadow: var(--shadow);
}
.stat-card-header {
  display: flex; align-items: center; justify-content: space-between;
  margin-bottom: 8px;
}
.stat-card-icon {
  width: 36px; height: 36px;
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
}
.stat-card-icon.blue { background: var(--primary-glow); color: var(--primary); }
.stat-card-icon.green { background: var(--success-glow); color: var(--success); }
.stat-card-icon.red { background: var(--danger-glow); color: var(--danger); }
.stat-card-icon.yellow { background: var(--warning-glow); color: var(--warning); }
.stat-card-icon.purple { background: var(--purple-glow); color: var(--purple); }
.stat-card-label {
  font-size: 0.75rem; color: var(--text-muted);
  text-transform: uppercase; letter-spacing: 0.5px;
}
.stat-card-value {
  font-size: 1.75rem; font-weight: 800; line-height: 1;
}
.stat-card-change {
  font-size: 0.75rem; margin-top: 4px;
}

/* ═══ MACHINE GRID ═══ */
.machines-section {
  flex: 1; min-height: 0;
}
.machines-section-header {
  display: flex; align-items: center; justify-content: space-between;
  margin-bottom: 12px;
}
.machines-section-title {
  font-size: 1rem; font-weight: 700;
}
.machines-filter {
  display: flex; gap: 6px;
}
.filter-btn {
  padding: 6px 14px; border-radius: 20px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border);
  color: var(--text-secondary);
  font-size: 0.75rem; font-weight: 600;
  cursor: pointer; transition: var(--transition);
}
.filter-btn:hover { background: rgba(255,255,255,0.08); }
.filter-btn.active {
  background: var(--primary-glow);
  border-color: var(--primary);
  color: var(--primary);
}

.machines-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 10px;
  overflow-y: auto; padding-bottom: 20px;
}
.machine-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 14px;
  cursor: pointer;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}
.machine-card::before {
  content: ''; position: absolute;
  top: 0; left: 0; right: 0; height: 3px;
  border-radius: var(--radius-sm) var(--radius-sm) 0 0;
}
.machine-card.running::before { background: var(--success); }
.machine-card.stopped::before { background: var(--danger); }
.machine-card.warning::before { background: var(--warning); }
.machine-card.offline::before { background: var(--text-muted); }
.machine-card.searching::before { background: var(--purple); }

.machine-card:hover {
  border-color: var(--border-active);
  transform: translateY(-3px);
  box-shadow: var(--shadow);
}
.machine-card.running { border-color: rgba(34, 197, 94, 0.15); }
.machine-card.stopped { border-color: rgba(239, 68, 68, 0.15); }
.machine-card.warning { border-color: rgba(245, 158, 11, 0.15); }
.machine-card.searching { border-color: rgba(168, 85, 247, 0.15); }

.machine-card-id {
  font-size: 0.95rem; font-weight: 800;
  margin-bottom: 6px;
}
.machine-card-status {
  font-size: 0.65rem; font-weight: 600;
  text-transform: uppercase; letter-spacing: 0.5px;
  margin-bottom: 8px;
}
.machine-card-status.running { color: var(--success); }
.machine-card-status.stopped { color: var(--danger); }
.machine-card-status.warning { color: var(--warning); }
.machine-card-status.offline { color: var(--text-muted); }
.machine-card-status.searching { color: var(--purple); }

.machine-card-meters {
  font-size: 0.75rem; color: var(--text-secondary);
}
.machine-card-meters span {
  font-weight: 700; color: var(--text);
}

.machine-card-pulse {
  position: absolute; top: 10px; right: 10px;
  width: 8px; height: 8px; border-radius: 50%;
}
.machine-card-pulse.running {
  background: var(--success);
  box-shadow: 0 0 8px var(--success);
  animation: pulse-dot 2s infinite;
}
.machine-card-pulse.stopped { background: var(--danger); }
.machine-card-pulse.offline { background: var(--text-muted); }
.machine-card-pulse.searching {
  background: var(--purple);
  box-shadow: 0 0 8px var(--purple);
  animation: pulse-dot 1.5s infinite;
}
@keyframes pulse-dot {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

/* ═══ MODAL ═══ */
.modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(8px);
  display: flex; align-items: center; justify-content: center;
  z-index: 100; padding: 20px;
  animation: modal-bg-in 0.2s ease;
}
@keyframes modal-bg-in {
  0% { opacity: 0; }
  100% { opacity: 1; }
}
.modal-content {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 28px;
  width: 100%; max-width: 480px;
  max-height: 85vh; overflow-y: auto;
  box-shadow: var(--shadow-lg);
  animation: modal-in 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
}
@keyframes modal-in {
  0% { opacity: 0; transform: scale(0.95) translateY(10px); }
  100% { opacity: 1; transform: scale(1) translateY(0); }
}
.modal-header {
  display: flex; align-items: center; justify-content: space-between;
  margin-bottom: 20px;
}
.modal-title {
  font-size: 1.25rem; font-weight: 800;
}
.modal-close {
  width: 32px; height: 32px;
  background: rgba(255,255,255,0.05);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text-muted);
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; transition: var(--transition);
}
.modal-close:hover {
  background: rgba(239, 68, 68, 0.1);
  border-color: rgba(239, 68, 68, 0.3);
  color: var(--danger);
}

/* ═══ TAB SWITCHER ═══ */
.tab-switcher {
  display: flex; gap: 4px;
  background: rgba(255,255,255,0.03);
  border-radius: 10px; padding: 4px;
  margin-bottom: 16px;
}
.tab-btn {
  flex: 1; padding: 8px 16px;
  background: transparent; border: none;
  color: var(--text-muted);
  font-size: 0.8rem; font-weight: 700;
  border-radius: 8px; cursor: pointer;
  transition: var(--transition);
}
.tab-btn:hover { color: var(--text); }
.tab-btn.active {
  background: var(--primary);
  color: #000;
}

/* ═══ INFO GRID ═══ */
.info-grid {
  display: grid; grid-template-columns: repeat(3, 1fr);
  gap: 10px; margin-bottom: 16px;
}
.info-item {
  background: rgba(255,255,255,0.03);
  border-radius: var(--radius-sm);
  padding: 12px; text-align: center;
}
.info-item-label {
  font-size: 0.65rem; color: var(--text-muted);
  text-transform: uppercase; letter-spacing: 0.5px;
  margin-bottom: 4px;
}
.info-item-value {
  font-size: 1.1rem; font-weight: 800;
}

/* ═══ DIAG BARS ═══ */
.diag-item {
  margin-bottom: 14px;
}
.diag-header {
  display: flex; justify-content: space-between;
  margin-bottom: 6px;
}
.diag-label {
  font-size: 0.75rem; color: var(--text-secondary); font-weight: 600;
}
.diag-value {
  font-size: 0.75rem; color: var(--text); font-weight: 600;
  font-family: 'JetBrains Mono', monospace;
}
.diag-bar-bg {
  height: 6px; background: rgba(255,255,255,0.05);
  border-radius: 3px; overflow: hidden;
}
.diag-bar {
  height: 100%; border-radius: 3px;
  transition: width 0.5s ease;
}
.diag-bar.ram { background: linear-gradient(90deg, #38bdf8, #0ea5e9); }
.diag-bar.rom { background: linear-gradient(90deg, #a855f7, #7c3aed); }

/* ═══ FORM ELEMENTS ═══ */
.input-field {
  width: 100%; padding: 12px 16px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text); font-size: 0.95rem;
  outline: none; transition: var(--transition);
  margin-bottom: 12px;
}
.input-field:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px var(--primary-glow);
}
.input-field::placeholder { color: var(--text-muted); }

.btn-primary {
  width: 100%; padding: 12px 20px;
  background: linear-gradient(135deg, var(--primary), #0099cc);
  color: #000; border: none;
  border-radius: var(--radius-sm);
  font-size: 0.9rem; font-weight: 700;
  cursor: pointer; transition: var(--transition);
}
.btn-primary:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 20px rgba(0, 210, 255, 0.3);
}
.btn-primary:active { transform: scale(0.98); }

.btn-secondary {
  width: 100%; padding: 12px 20px;
  background: rgba(255,255,255,0.05);
  border: 1px solid var(--border);
  color: var(--text); border-radius: var(--radius-sm);
  font-size: 0.9rem; font-weight: 600;
  cursor: pointer; transition: var(--transition);
}
.btn-secondary:hover { background: rgba(255,255,255,0.08); }

.btn-danger {
  width: 100%; padding: 12px 20px;
  background: rgba(239, 68, 68, 0.1);
  border: 1px solid rgba(239, 68, 68, 0.2);
  color: var(--danger); border-radius: var(--radius-sm);
  font-size: 0.9rem; font-weight: 600;
  cursor: pointer; transition: var(--transition);
}
.btn-danger:hover { background: rgba(239, 68, 68, 0.2); }

.btn-success {
  width: 100%; padding: 12px 20px;
  background: rgba(34, 197, 94, 0.15);
  border: 1px solid rgba(34, 197, 94, 0.3);
  color: var(--success); border-radius: var(--radius-sm);
  font-size: 0.9rem; font-weight: 700;
  cursor: pointer; transition: var(--transition);
}
.btn-success:hover { background: rgba(34, 197, 94, 0.25); }

/* ═══ SOURCE SWITCHER ═══ */
.source-switcher {
  display: flex; gap: 4px;
  background: rgba(0,0,0,0.3);
  border-radius: 8px; padding: 3px;
  margin-bottom: 16px;
}
.source-btn {
  flex: 1; padding: 6px 12px;
  background: transparent; border: none;
  color: var(--text-muted);
  font-size: 0.7rem; font-weight: 700;
  border-radius: 6px; cursor: pointer;
  transition: var(--transition);
  text-transform: uppercase;
}
.source-btn.active {
  background: var(--primary);
  color: #000;
}

/* ═══ LOGIN ═══ */
.login-page {
  display: flex; justify-content: center; align-items: center;
  height: 100vh; height: 100dvh;
  background: var(--bg);
  background-image: radial-gradient(circle at 50% 30%, rgba(0, 210, 255, 0.05) 0%, transparent 50%);
  padding: 20px;
}
.login-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 24px;
  padding: 40px 32px;
  width: 100%; max-width: 400px;
  box-shadow: var(--shadow-lg);
}
.login-header {
  text-align: center; margin-bottom: 28px;
}
.login-icon {
  width: 64px; height: 64px;
  background: linear-gradient(135deg, var(--primary), var(--purple));
  border-radius: 16px;
  display: flex; align-items: center; justify-content: center;
  margin: 0 auto 16px;
}
.login-title {
  font-size: 1.5rem; font-weight: 800;
  background: linear-gradient(135deg, var(--primary), var(--purple));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
}
.login-subtitle {
  color: var(--text-muted); font-size: 0.85rem; margin-top: 4px;
}
.login-error {
  background: rgba(239, 68, 68, 0.08);
  border: 1px solid rgba(239, 68, 68, 0.2);
  color: var(--danger);
  padding: 12px 16px; border-radius: var(--radius-sm);
  font-size: 0.85rem; font-weight: 600;
  margin-bottom: 16px;
}
.login-field { margin-bottom: 16px; }
.login-field label {
  display: block; font-size: 0.8rem; font-weight: 600;
  color: var(--text-secondary); margin-bottom: 6px;
}
.login-field input {
  width: 100%; padding: 12px 16px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text); font-size: 0.95rem;
  outline: none; transition: var(--transition);
}
.login-field input:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px var(--primary-glow);
}
.login-field input::placeholder { color: var(--text-muted); }

/* ═══ PANELS ═══ */
.panel-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  margin-bottom: 16px;
}
.panel-title {
  font-size: 1rem; font-weight: 700;
  margin-bottom: 16px;
  display: flex; align-items: center; gap: 8px;
}

/* ═══ TABLE ═══ */
.data-table {
  width: 100%; border-collapse: collapse;
}
.data-table th {
  text-align: left; padding: 10px 12px;
  font-size: 0.7rem; font-weight: 700;
  color: var(--text-muted); text-transform: uppercase;
  letter-spacing: 0.5px;
  border-bottom: 1px solid var(--border);
}
.data-table td {
  padding: 10px 12px;
  font-size: 0.85rem;
  border-bottom: 1px solid rgba(255,255,255,0.03);
}
.data-table tr:hover td {
  background: rgba(255,255,255,0.02);
}

/* ═══ BADGE ═══ */
.badge {
  display: inline-flex; align-items: center;
  padding: 3px 10px; border-radius: 20px;
  font-size: 0.7rem; font-weight: 700;
  text-transform: uppercase; letter-spacing: 0.3px;
}
.badge-success { background: var(--success-glow); color: var(--success); }
.badge-danger { background: var(--danger-glow); color: var(--danger); }
.badge-warning { background: var(--warning-glow); color: var(--warning); }
.badge-info { background: var(--primary-glow); color: var(--primary); }
.badge-purple { background: var(--purple-glow); color: var(--purple); }

/* ═══ MOBILE ═══ */
@media (max-width: 768px) {
  .sidebar { display: none; }
  .app-container { flex-direction: column; }
  .main-content { padding: 12px; padding-bottom: 80px; }
  .stats-row { grid-template-columns: repeat(2, 1fr); gap: 8px; }
  .stat-card { padding: 12px; }
  .stat-card-value { font-size: 1.3rem; }
  .machines-grid { grid-template-columns: repeat(auto-fill, minmax(110px, 1fr)); gap: 8px; }
  .machine-card { padding: 10px; }
  .modal-content { padding: 20px; border-radius: 20px 20px 0 0; }
  .modal-overlay { align-items: flex-end; padding: 0; }
  .info-grid { grid-template-columns: repeat(3, 1fr); gap: 6px; }
  .page-title { font-size: 1.2rem; }
}

/* ═══ MOBILE BOTTOM BAR ═══ */
.mobile-bottom-bar {
  display: none;
  position: fixed; bottom: 0; left: 0; right: 0;
  z-index: 999;
  background: rgba(13, 17, 23, 0.95);
  backdrop-filter: blur(20px);
  border-top: 1px solid var(--border);
  padding: 6px 8px;
  padding-bottom: max(6px, env(safe-area-inset-bottom));
}
@media (max-width: 768px) {
  .mobile-bottom-bar { display: block; }
}
