  padding: 6px 8px; border-radius: 10px;
  cursor: pointer; transition: var(--transition);
  min-width: 48px;
}
.mobile-tab-btn.active { color: var(--primary); }
.mobile-tab-btn:active { transform: scale(0.9); }
.mobile-tab-label { font-size: 0.55rem; font-weight: 600; }

/* ═══ ANIMATIONS ═══ */
@keyframes fadeIn { 0% { opacity: 0; } 100% { opacity: 1; } }
@keyframes slideUp { 0% { opacity: 0; transform: translateY(10px); } 100% { opacity: 1; transform: translateY(0); } }
