          <div className="stat-card-header">
            <div className="stat-card-icon red">
              <AlertTriangle size={18} />
            </div>
            <div className="stat-card-label">To'xtagan</div>
          </div>
          <div className="stat-card-value" style={{ color: 'var(--danger)' }}>{stats.stopped}</div>
        </div>

        <div className="stat-card">
          <div className="stat-card-header">
            <div className="stat-card-icon yellow">
              <Signal size={18} />
            </div>
            <div className="stat-card-label">Signal yo'q</div>
          </div>
          <div className="stat-card-value" style={{ color: 'var(--warning)' }}>{stats.warning}</div>
        </div>
      </div>

      {/* Filters */}
      <div className="machines-section-header">
        <div className="machines-section-title">Stanoklar</div>
        <div className="machines-filter">
          <button 
            className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            Barchasi
          </button>
          <button 
            className={`filter-btn ${filter === 'RUNNING' ? 'active' : ''}`}
            onClick={() => setFilter('RUNNING')}
          >
            Ishlayotgan
          </button>
          <button 
            className={`filter-btn ${filter === 'OFFLINE' ? 'active' : ''}`}
            onClick={() => setFilter('OFFLINE')}
          >
            Offline
          </button>
          <button 
            className={`filter-btn ${filter === 'ASNOVA_EMPTY' ? 'active' : ''}`}
            onClick={() => setFilter('ASNOVA_EMPTY')}
          >
            Asnova tugagan
          </button>
        </div>
      </div>

      {/* Machines Grid/List */}
      <div className="machines-section">
        {viewMode === 'grid' ? (
          <div className="machines-grid">
            {filteredMachines.map(machine => (
              <MachineCard key={machine.id} machine={machine} />
            ))}
          </div>
        ) : (
          <div className="machines-list">
            {filteredMachines.map(machine => (
              <MachineListItem key={machine.id} machine={machine} />
            ))}
          </div>
        )}
      </div>

      {/* Machine Detail Modal */}
      {selectedMachine && (
        <div className="modal-overlay" onClick={() => setSelectedMachine(null)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2 className="modal-title">Stanok {selectedMachine.id}</h2>
              <button className="modal-close" onClick={() => setSelectedMachine(null)}>
                <X size={18} />
              </button>
            </div>

            <div className="tab-switcher">
              <button 
                className={`tab-btn ${activeTab === 'info' ? 'active' : ''}`}
                onClick={() => setActiveTab('info')}
              >
                <Info size={14} />
                <span>Ma'lumot</span>
              </button>
              <button 
                className={`tab-btn ${activeTab === 'diag' ? 'active' : ''}`}
                onClick={() => setActiveTab('diag')}
              >
                <Cpu size={14} />
                <span>Diagnostika</span>
              </button>
              <button 
                className={`tab-btn ${activeTab === 'settings' ? 'active' : ''}`}
                onClick={() => setActiveTab('settings')}
              >
                <Settings size={14} />
                <span>Sozlamalar</span>
              </button>
            </div>

            {activeTab === 'info' && (
              <div className="machine-info">
                <div className="info-grid">
                  <div className="info-item">
                    <div className="info-item-label">Holat</div>
                    <div className="info-item-value" style={{ color: getStatusColor(selectedMachine.status) }}>
                      {getStatusText(selectedMachine.status)}
                    </div>
                  </div>
                  <div className="info-item">
                    <div className="info-item-label">Smena metrlar</div>
                    <div className="info-item-value">{selectedMachine.shift_meters?.toFixed(1) || 0}m</div>
                  </div>
                  <div className="info-item">
                    <div className="info-item-label">Asnova qoldiq</div>
                    <div className="info-item-value">{selectedMachine.remaining?.toFixed(1) || 0}m</div>
                  </div>
                </div>

                <div className="info-details">
                  <div className="detail-row">
                    <span className="detail-label">Signal</span>
                    <span className="detail-value">{selectedMachine.baud || 0} BPS</span>
                  </div>
                  <div className="detail-row">
                    <span className="detail-label">Protokol</span>
                    <span className="detail-value">{selectedMachine.protocol || 'N/A'}</span>
                  </div>
                  <div className="detail-row">
                    <span className="detail-label">Ulanish</span>
                    <span className="detail-value">{selectedMachine.connection_source}</span>
                  </div>
                  <div className="detail-row">
                    <span className="detail-label">Oxirgi ko'rilgan</span>
                    <span className="detail-value">
                      {selectedMachine.last_seen ? new Date(selectedMachine.last_seen).toLocaleString('uz-UZ') : 'N/A'}
                    </span>
                  </div>
                </div>

                {(selectedMachine.remaining <= 0 || user.role === 'ADMIN' || user.role === 'UZLAVYAZ') && (
                  <div className="asnova-fill">
                    <h4>Asnova to'ldirish</h4>
                    <div className="asnova-form">
                      <input
                        type="number"
                        className="input-field"
                        placeholder="Yangi asnova uzunligi (metr)"
                        value={asnovaLength}
                        onChange={(e) => setAsnovaLength(e.target.value)}
                      />
                      <button className="btn-primary" onClick={handleFillAsnova}>
                        To'ldirish
                      </button>
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'diag' && (
              <div className="machine-diag">
                <div className="diag-item">
                  <div className="diag-header">
                    <span className="diag-label">RAM (Heap)</span>
                    <span className="diag-value">
                      {((selectedMachine.sys_info?.ram?.free / 1048576) || 0).toFixed(2)} MB / 
                      {((selectedMachine.sys_info?.ram?.total / 1048576) || 0).toFixed(2)} MB
                    </span>
                  </div>
                  <div className="diag-bar-bg">
                    <div 
                      className="diag-bar ram" 
                      style={{ 
                        width: `${(selectedMachine.sys_info?.ram?.total ? 
                          (selectedMachine.sys_info.ram.free / selectedMachine.sys_info.ram.total * 100) : 0)}%` 
                      }}
                    ></div>
                  </div>
                </div>

                <div className="diag-item">
                  <div className="diag-header">
                    <span className="diag-label">ROM (Flash)</span>
                    <span className="diag-value">
                      {((selectedMachine.sys_info?.rom?.free / 1048576) || 0).toFixed(2)} MB / 
                      {((selectedMachine.sys_info?.rom?.total / 1048576) || 0).toFixed(2)} MB
                    </span>
                  </div>
                  <div className="diag-bar-bg">
                    <div 
                      className="diag-bar rom" 
                      style={{ 
                        width: `${(selectedMachine.sys_info?.rom?.total ? 
                          (selectedMachine.sys_info.rom.free / selectedMachine.sys_info.rom.total * 100) : 0)}%` 
                      }}
                    ></div>
                  </div>
                </div>

                <div className="diag-grid">
                  <div className="diag-card">
                    <Cpu size={16} />
                    <div className="diag-card-label">CPU</div>
                    <div className="diag-card-value">{selectedMachine.sys_info?.cpu || 0} MHz</div>
                  </div>
                  <div className="diag-card">
                    <Wifi size={16} />
                    <div className="diag-card-label">WiFi RSSI</div>
                    <div className="diag-card-value">{selectedMachine.sys_info?.wifi?.rssi || 0} dBm</div>
                  </div>
                  <div className="diag-card">
                    <Signal size={16} />
                    <div className="diag-card-label">SSID</div>
                    <div className="diag-card-value">{selectedMachine.sys_info?.wifi?.ssid || 'N/A'}</div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'settings' && (
              <div className="machine-settings">
                <h4>Ulanish manbasi</h4>
                <div className="source-switcher">
                  {['AUTO', 'USB', 'WIFI'].map(source => (
                    <button
                      key={source}
                      className={`source-btn ${selectedMachine.preferred_source === source ? 'active' : ''}`}
                      onClick={() => handleSourceChange(selectedMachine.id, source)}
                    >
                      {source}
                    </button>
                  ))}
                </div>

                <div className="settings-info">
                  <p>Joriy manba: <strong>{selectedMachine.connection_source}</strong></p>
                  <p>Preferred manba: <strong>{selectedMachine.preferred_source}</strong></p>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;","isOutsideWorkspace":false,"isProtected":false,"id":"unified_1775141251285_write_0"}

